const svg = $('#specz-svg');
const W=820,H=210;
const xs = p => 40 + (PRIMES.indexOf(p))*30.5;
// axis
const axis = SVG('line',{x1:20,y1:150,x2:800,y2:150,stroke:'#3a4558','stroke-width':1});
svg.appendChild(axis);
// generic point: dashed horizontal band
const generic = SVG('line',{x1:20,y1:60,x2:800,y2:60,stroke:'#b39ddb','stroke-width':1.2,'stroke-dasharray':'5 5'});
svg.appendChild(generic);
const genLabel = SVG('text',{x:20,y:48,'font-size':13,fill:'#b39ddb'});
genLabel.textContent='generic point (0)  — value of n in ℚ';
svg.appendChild(genLabel);

// for each prime, a dot + label
const dots=[], glows=[], labels=[];
PRIMES.forEach((p,i)=>{
  const x = xs(p);
  const g = SVG('g',{});
  const glow = SVG('circle',{cx:x,cy:150,r:3,fill:'#ffd866','fill-opacity':0,stroke:'#ffd866','stroke-opacity':0});
  const dot = SVG('circle',{cx:x,cy:150,r:3.5,fill:'#58c4dd',stroke:'#e8ecf1','stroke-width':1,'data-p':p,style:'cursor:pointer'});
  const lbl = SVG('text',{x:x,y:172,'font-size':11,'text-anchor':'middle',fill:'#9aa4b2'});
  lbl.textContent = p;
  g.appendChild(glow); g.appendChild(dot); g.appendChild(lbl);
  svg.appendChild(g);
  glows.push(glow); dots.push(dot); labels.push(lbl);

  dot.addEventListener('mouseenter',()=>showValueAt(p));
  dot.addEventListener('mouseleave',()=>hideValue());
});

// generic point value readout (when hovering generic line)
generic.style.cursor='pointer';
genLabel.style.cursor='pointer';
[generic,genLabel].forEach(el=>{
  el.addEventListener('mouseenter',()=>showGenericValue());
  el.addEventListener('mouseleave',()=>hideValue());
});

// ghost "vertical connection" drawn for primes dividing n
const connGroup = SVG('g',{});
svg.appendChild(connGroup);

const input = $('#specz-n');
const factSpan = $('#specz-fact');
const readout = $('#specz-readout');

function update(){
  const n = parseInt(input.value,10);
  if(!Number.isFinite(n)){return}
  const factors = factorize(n);
  if(n===0){
    factSpan.innerHTML = '<span style="color:var(--pink)">0 vanishes at every prime</span>';
  } else if(Math.abs(n)===1){
    factSpan.innerHTML = '<span style="color:var(--green)">±1 is a unit — never vanishes</span>';
  } else {
    factSpan.innerHTML = 'factorization: '+factors.map(([p,e])=>e===1?p:`${p}<sup>${e}</sup>`).join(' · ');
  }
  // clear connections
  while(connGroup.firstChild) connGroup.removeChild(connGroup.firstChild);
  // style each prime dot
  PRIMES.forEach((p,i)=>{
    const dot=dots[i], glow=glows[i], lbl=labels[i];
    const entry = factors.find(([q,e])=>q===p);
    if(n===0){
      dot.setAttribute('fill','#e07a5f'); dot.setAttribute('r',6);
      glow.setAttribute('fill-opacity',0.2); glow.setAttribute('r',12);
      glow.setAttribute('stroke-opacity',0.4);
      lbl.setAttribute('fill','#f4d2c7');
    } else if(entry){
      const e=entry[1];
      const r = 4 + 3*Math.min(e,5);
      dot.setAttribute('fill','#ffd866'); dot.setAttribute('r',r);
      glow.setAttribute('fill','#ffd866'); glow.setAttribute('fill-opacity',0.18);
      glow.setAttribute('r',r+6+2*e);
      glow.setAttribute('stroke-opacity',0.5);
      lbl.setAttribute('fill','#ffd866');
      // draw connection line from generic to this prime
      const x = xs(p);
      const line = SVG('line',{x1:x,y1:61,x2:x,y2:150,stroke:'#ffd866','stroke-width':1,'stroke-opacity':0.5,'stroke-dasharray':'2 3'});
      connGroup.appendChild(line);
      const tag = SVG('text',{x:x,y:105,'font-size':10,'text-anchor':'middle',fill:'#ffd866'});
      tag.textContent = e>1? `ord=${e}` : '';
      connGroup.appendChild(tag);
    } else {
      dot.setAttribute('fill','#58c4dd'); dot.setAttribute('r',3.5);
      glow.setAttribute('fill-opacity',0);
      glow.setAttribute('stroke-opacity',0);
      lbl.setAttribute('fill','#9aa4b2');
    }
  });
}
function showValueAt(p){
  const n = parseInt(input.value,10);
  const v = mod(n,p);
  readout.innerHTML = `value of n=${n} at prime (${p}): &nbsp; ${n} mod ${p} = <span style="color:var(--yellow)">${v}</span>` +
    (v===0?`<span style="color:var(--green)"> — vanishes here</span>`:'') +
    `<br><span class="small">residue field κ((${p})) = 𝔽<sub>${p}</sub></span>`;
}
function showGenericValue(){
  const n = parseInt(input.value,10);
  readout.innerHTML = `value of n=${n} at the generic point (0): &nbsp; <span style="color:var(--violet)">${n} ∈ ℚ</span>` +
    `<br><span class="small">residue field κ((0)) = ℚ. The generic point "sees" n itself.</span>`;
}
function hideValue(){
  readout.innerHTML = `Hover a dot to see $n \\bmod p$; the orange glow encodes multiplicity of $p$ in $n$.`;
  if(window.renderMathInElement) renderMathInElement(readout,{delimiters:[{left:'$',right:'$',display:false}]});
}
input.addEventListener('input',update);
update();

