input.addEventListener('input',update);
update();

const svg = $('#speckx-svg');
const W=820,H=320;
const ro = $('#speckx-readout');
// complex roots via Durand-Kerner
function roots(coeffs){
  // coeffs = [a0,a1,...,an], highest nonzero at end
  // normalize and trim trailing zeros
  let c = coeffs.slice();
  while(c.length>1 && c[c.length-1]===0) c.pop();
  const n = c.length-1;
  if(n<=0) return []; // constant
  const an = c[n];
  const p = c.map(x=>x/an); // monic
  // initial guesses on a circle
  const zs = [];
  for(let k=0;k<n;k++){
    const th = 2*Math.PI*k/n + 0.4;
    zs.push([Math.cos(th)*1.3,Math.sin(th)*1.3]);
  }
  const cmul=([a,b],[c,d])=>[a*c-b*d,a*d+b*c];
  const cadd=([a,b],[c,d])=>[a+c,b+d];
  const csub=([a,b],[c,d])=>[a-c,b-d];
  const cdiv=([a,b],[c,d])=>{const r=c*c+d*d;return [(a*c+b*d)/r,(b*c-a*d)/r]};
  function eval_(p,z){let y=[0,0];for(let i=p.length-1;i>=0;i--){y=cadd(cmul(y,z),[p[i],0])}return y;}
  for(let iter=0; iter<200; iter++){
    let moved=0;
    for(let k=0;k<n;k++){
      const fz = eval_(p,zs[k]);
      let denom=[1,0];
      for(let j=0;j<n;j++) if(j!==k) denom = cmul(denom, csub(zs[k],zs[j]));
      const step = cdiv(fz,denom);
      zs[k] = csub(zs[k],step);
      moved += Math.abs(step[0])+Math.abs(step[1]);
    }
    if(moved<1e-12) break;
  }
  return zs;
}
// cluster roots within tol
function cluster(zs,tol=1e-4){
  const out=[];
  for(const z of zs){
    const hit = out.find(o=>Math.hypot(o.z[0]-z[0],o.z[1]-z[1])<tol);
    if(hit){hit.m++}
    else out.push({z,m:1});
  }
  return out;
}

// UI state
let field='C';
$$('.fbtn',$('#w-speckx')).forEach(b=>b.addEventListener('click',()=>{
  $$('.fbtn',$('#w-speckx')).forEach(x=>x.classList.remove('active'));
  b.classList.add('active'); field=b.dataset.f; draw();
}));
$$('.pbtn',$('#w-speckx')).forEach(b=>b.addEventListener('click',()=>{
  const [c0,c1,c2,c3] = b.dataset.c.split(',').map(Number);
  $('#c0').value=c0; $('#c1').value=c1; $('#c2').value=c2; $('#c3').value=c3; draw();
}));
['c0','c1','c2','c3'].forEach(id=>$('#'+id).addEventListener('input',draw));

function coeffArr(){
  return [+$('#c0').value,+$('#c1').value,+$('#c2').value,+$('#c3').value];
}
function polyStr(c){
  const terms=[];
  for(let i=c.length-1;i>=0;i--){
    if(c[i]===0) continue;
    let s = Math.abs(c[i])===1 && i>0 ? '' : `${Math.abs(c[i])}`;
    const xp = i===0?'':(i===1?'x':`x${sup(i)}`);
    terms.push((c[i]<0? (terms.length?' − ':'−') : (terms.length?' + ':'')) + s + xp);
  }
  return terms.join('')||'0';
}
function sup(n){return ''+[...String(n)].map(d=>'⁰¹²³⁴⁵⁶⁷⁸⁹'[+d]).join('')}

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const c = coeffArr();
  // always draw in a plane
  const cx=W/2, cy=H/2+10, sx=100, sy=100;
  const tx = a => cx + a*sx;
  const ty = b => cy - b*sy;

  // axes
  svg.appendChild(SVG('line',{x1:40,y1:cy,x2:W-20,y2:cy,stroke:'#3a4558'}));
  svg.appendChild(SVG('line',{x1:cx,y1:30,x2:cx,y2:H-30,stroke:'#3a4558'}));
  for(let a=-3;a<=3;a++){
    svg.appendChild(SVG('line',{x1:tx(a),y1:cy-4,x2:tx(a),y2:cy+4,stroke:'#3a4558'}));
    if(a!==0){const t=SVG('text',{x:tx(a),y:cy+18,'font-size':11,'text-anchor':'middle',fill:'#6c7787'});t.textContent=a;svg.appendChild(t)}
  }
  if(field!=='F5' && field!=='F7'){
    for(let b=-1;b<=1;b++){if(b===0)continue;
      svg.appendChild(SVG('line',{x1:cx-4,y1:ty(b),x2:cx+4,y2:ty(b),stroke:'#3a4558'}));
      const t=SVG('text',{x:cx+8,y:ty(b)+4,'font-size':11,fill:'#6c7787'});t.textContent=b+'i';svg.appendChild(t);
    }
  }
  // axis labels
  const lbl = SVG('text',{x:W-30,y:cy-8,'font-size':12,fill:'#9aa4b2','text-anchor':'end'});
  lbl.textContent= (field==='F5'||field==='F7')?'residue':'Re';
  svg.appendChild(lbl);
  if(field!=='F5' && field!=='F7'){
    const lbl2 = SVG('text',{x:cx+8,y:40,'font-size':12,fill:'#9aa4b2'});
    lbl2.textContent='Im'; svg.appendChild(lbl2);
  }

  // generic point marker
  const gp = SVG('text',{x:50,y:50,'font-size':12,fill:'#b39ddb'});
  gp.textContent='· generic point (0), residue field = '+(field==='C'?'ℂ(x)':field==='R'?'ℝ(x)':field==='F5'?'𝔽₅(x)':'𝔽₇(x)');
  svg.appendChild(gp);

  if(field==='F5' || field==='F7'){
    const q = field==='F5'?5:7;
    // evaluate p(x) mod q at each residue
    const dots=[];
    for(let a=0;a<q;a++){
      let v=0;
      for(let i=c.length-1;i>=0;i--){v=mod(v*a+c[i],q)}
      const x = 120 + a*100;
      const dot = SVG('circle',{cx:x,cy:cy,r: v===0?10:5,fill: v===0?'#ffd866':'#58c4dd','data-a':a,'data-v':v,style:'cursor:pointer'});
      const lbl = SVG('text',{x,y:cy+26,'font-size':12,'text-anchor':'middle',fill: v===0?'#ffd866':'#9aa4b2'});
      lbl.textContent = `x=${a}`;
      dot.addEventListener('mouseenter',()=>{
        ro.innerHTML = `at closed point $(x-${a})$:&nbsp; p(${a}) mod ${q} = <span style="color:var(--yellow)">${v}</span>`+
          (v===0?` <span style="color:var(--green)">— root!</span>`:``) +
          `<br><span class="small">residue field = 𝔽<sub>${q}</sub></span>`;
        if(window.renderMathInElement) renderMathInElement(ro,{delimiters:[{left:'$',right:'$',display:false}]});
      });
      svg.appendChild(dot); svg.appendChild(lbl);
    }
    // summary: note about higher-degree primes
    const note = SVG('text',{x:W/2,y:H-15,'font-size':11,'text-anchor':'middle',fill:'#9aa4b2'});
    note.textContent='closed points shown: degree-1 primes (x−a). Higher-degree irreducibles exist but aren\u2019t drawn.';
    svg.appendChild(note);
    return;
  }

  // find complex roots (mass ~ multiplicity via clustering)
  const rawRoots = roots(c);
  const clusters = cluster(rawRoots, 0.02);
  // organize for R: pair conjugates
  if(field==='R'){
    const used = new Array(clusters.length).fill(false);
    const real = [], pairs = [];
    for(let i=0;i<clusters.length;i++){
      if(used[i]) continue;
      const {z,m} = clusters[i];
      if(Math.abs(z[1])<0.01){ real.push({a:z[0],m}); used[i]=true; }
      else {
        // find conjugate
        let j=-1,best=Infinity;
        for(let k=i+1;k<clusters.length;k++){
          if(used[k]) continue;
          const w=clusters[k].z;
          const d=Math.hypot(w[0]-z[0],w[1]+z[1]);
          if(d<best){best=d;j=k}
        }
        if(j>=0 && best<0.05){
          pairs.push({a:z[0],b:Math.abs(z[1]),m}); used[i]=used[j]=true;
        } else {
          pairs.push({a:z[0],b:Math.abs(z[1]),m}); used[i]=true;
        }
      }
    }
    // draw real roots on axis
    for(const {a,m} of real){
      const x=tx(a);
      const d = SVG('circle',{cx:x,cy:cy,r:5+2*m,fill:'#ffd866',style:'cursor:pointer'});
      d.addEventListener('mouseenter',()=>{
        ro.innerHTML = `closed point <span style="color:var(--yellow)">$(x - ${a.toFixed(3)})$</span> · multiplicity ${m} · residue field ℝ`;
        if(window.renderMathInElement) renderMathInElement(ro,{delimiters:[{left:'$',right:'$',display:false}]});
      });
      svg.appendChild(d);
    }
    // draw conjugate pairs: one "point" bracketing two dots above/below
    for(const {a,b,m} of pairs){
      const x=tx(a), yp=ty(b), yn=ty(-b);
      // bracket
      svg.appendChild(SVG('path',{d:`M ${x-12} ${yp} L ${x-18} ${yp} L ${x-18} ${yn} L ${x-12} ${yn}`,fill:'none',stroke:'#e07a5f','stroke-width':1.5}));
      const top = SVG('circle',{cx:x,cy:yp,r:4+2*m,fill:'#e07a5f',opacity:0.8});
      const bot = SVG('circle',{cx:x,cy:yn,r:4+2*m,fill:'#e07a5f',opacity:0.8});
      svg.appendChild(top); svg.appendChild(bot);
      // label: one point of Spec R[x]
      const tag = SVG('text',{x:x-22,y:(yp+yn)/2+4,'font-size':11,'text-anchor':'end',fill:'#e07a5f'});
      tag.textContent='1 point';
      svg.appendChild(tag);
      [top,bot].forEach(el=>{
        el.style.cursor='pointer';
        el.addEventListener('mouseenter',()=>{
          const B=b.toFixed(3), A=a.toFixed(3);
          ro.innerHTML = `closed point <span style="color:var(--pink)">$(x^2 - 2·${A}·x + (${A}^2 + ${B}^2))$</span> — irreducible over ℝ<br>` +
            `<span class="small">residue field ℂ · the two complex conjugates ${A} ± ${B}i are "one" prime over ℝ</span>`;
          if(window.renderMathInElement) renderMathInElement(ro,{delimiters:[{left:'$',right:'$',display:false}]});
        });
      });
    }
    return;
  }
  // field === 'C': draw every root in plane
  for(const {z,m} of clusters){
    const x=tx(z[0]), y=ty(z[1]);
    const d = SVG('circle',{cx:x,cy:y,r:5+2*m,fill:'#ffd866',stroke:'#fff','stroke-width':0.5,style:'cursor:pointer'});
    d.addEventListener('mouseenter',()=>{
      const im = z[1]>=0? `+ ${z[1].toFixed(3)}i` : `− ${(-z[1]).toFixed(3)}i`;
      ro.innerHTML = `closed point <span style="color:var(--yellow)">$(x - (${z[0].toFixed(3)} ${im}))$</span> · multiplicity ${m} · residue field ℂ`;
      if(window.renderMathInElement) renderMathInElement(ro,{delimiters:[{left:'$',right:'$',display:false}]});
    });
    svg.appendChild(d);
  }
}
draw();

