// render implicit curve f(x,y)=0 as pixel-level zero crossings → path segments
function drawCurve(cdef,color,width=1.6,dim=false){
  // sample on a grid, use marching squares-ish: draw a line where sign changes on a cell edge
  const N=220;
  const step = W/N;
  const vals = new Float32Array((N+1)*(N+1));
  for(let j=0;j<=N;j++){
    for(let i=0;i<=N;i++){
      const x = xfromPx(i*step);
      const y = yfromPx(j*step);
      vals[j*(N+1)+i] = cdef.f(x,y);
    }
  }
  const path = [];
  for(let j=0;j<N;j++){
    for(let i=0;i<N;i++){
      const a = vals[j*(N+1)+i];
      const b = vals[j*(N+1)+i+1];
      const c = vals[(j+1)*(N+1)+i];
      const d = vals[(j+1)*(N+1)+i+1];
      // connect zero crossings on the 4 edges of this cell, pair them
      const pts = [];
      if((a<=0)!==(b<=0)){const t=a/(a-b);pts.push([(i+t)*step, j*step])}
      if((b<=0)!==(d<=0)){const t=b/(b-d);pts.push([(i+1)*step, (j+t)*step])}
      if((c<=0)!==(d<=0)){const t=c/(c-d);pts.push([(i+t)*step, (j+1)*step])}
      if((a<=0)!==(c<=0)){const t=a/(a-c);pts.push([i*step, (j+t)*step])}
      if(pts.length>=2){
        // connect first two (fine for smooth curves)
        path.push([pts[0],pts[1]]);
        if(pts.length===4) path.push([pts[2],pts[3]]);
      }
    }
  }
  const g = SVG('g',{});
  for(const [p,q] of path){
    g.appendChild(SVG('line',{x1:p[0],y1:p[1],x2:q[0],y2:q[1],stroke:color,'stroke-width':width,'stroke-opacity':dim?0.35:0.95,'stroke-linecap':'round'}));
  }
  svg.appendChild(g);
  return g;
}

