    g.appendChild(SVG('line',{x1:p[0],y1:p[1],x2:q[0],y2:q[1],stroke:color,'stroke-width':width,'stroke-opacity':dim?0.35:0.95,'stroke-linecap':'round'}));
  }
  svg.appendChild(g);
  return g;
}

// crosshair
const crosshair = SVG('g',{});
const chV = SVG('line',{x1:0,y1:0,x2:0,y2:H,stroke:'#e07a5f','stroke-width':1,'stroke-opacity':0.4,'stroke-dasharray':'3 4'});
const chH = SVG('line',{x1:0,y1:0,x2:W,y2:0,stroke:'#e07a5f','stroke-width':1,'stroke-opacity':0.4,'stroke-dasharray':'3 4'});
const chD = SVG('circle',{r:5,fill:'#e07a5f',stroke:'#fff','stroke-width':1});
crosshair.appendChild(chV); crosshair.appendChild(chH); crosshair.appendChild(chD);
let mouseMath = {x:0.7,y:0.49}; // start on parabola

const colorMap = ['#58c4dd','#ffd866','var(--green)','#e07a5f','#b39ddb','#7de0d6','#f78fb3'];

function redraw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  drawAxes();
  // generic-point veil — very faint purple noise-free glow over plane
  svg.appendChild(SVG('rect',{x:0,y:0,width:W,height:H,fill:'url(#noop)','opacity':0}));
  // active curves
  const drawn = [];
  let idx=0;
  for(const c of curves){
    if(!active.has(c.id)) continue;
    const col = colorMap[idx%colorMap.length]; idx++;
    // test if crosshair is near curve
    const val = c.f(mouseMath.x, mouseMath.y);
    const near = Math.abs(val) < 0.08;
    drawCurve(c,col,near?2.8:1.8, !near && active.size>1 && false);
    drawn.push({c,col,near});
  }
  // legend
  const lg = SVG('g',{});
  let ly=22;
  for(const {c,col,near} of drawn){
    const r = SVG('rect',{x:20,y:ly-10,width:10,height:10,fill:col,opacity:near?1:0.85});
    const t = SVG('text',{x:36,y:ly-1,'font-size':12,fill:near?'#fff':'#cbd5e1'});
    t.textContent = c.label + (near?'  ← near crosshair':'');
    lg.appendChild(r); lg.appendChild(t); ly+=18;
  }
  svg.appendChild(lg);
  // crosshair
  chV.setAttribute('x1', tx(mouseMath.x)); chV.setAttribute('x2', tx(mouseMath.x));
  chH.setAttribute('y1', ty(mouseMath.y)); chH.setAttribute('y2', ty(mouseMath.y));
  chD.setAttribute('cx', tx(mouseMath.x)); chD.setAttribute('cy', ty(mouseMath.y));
  svg.appendChild(crosshair);

  // readout: what's at (a,b)
  const a = mouseMath.x.toFixed(3), b = mouseMath.y.toFixed(3);
  const hits = drawn.filter(d=>d.near).map(d=>d.c.label);
  const genericCurves = drawn.filter(d=>d.near).map(d=>
    `<div>· generic point of curve: <span style="color:${d.col}">$(${d.c.fStr.replace(/−/g,'-')})$</span> — residue field = Frac(k[x,y]/(${d.c.fStr}))</div>`
  ).join('');
  ro.innerHTML = `<div>closed point $\\mathfrak{m}=(x-${a},\\,y-${b})$ · residue field = k</div>` +
    (hits.length?`<div class="small" style="color:var(--green)">this point lies on ${hits.length} selected curve(s)</div>${genericCurves}`:`<div class="small">no active curve passes through this point</div>`) +
    `<div class="small" style="margin-top:.4rem;color:var(--violet)">above all of these: the 2-dim generic point (0) — residue field k(x,y)</div>`;
  if(window.renderMathInElement) renderMathInElement(ro,{delimiters:[{left:'$',right:'$',display:false}]});
}

svg.addEventListener('mousemove',e=>{
  const r = svg.getBoundingClientRect();
  const px = (e.clientX-r.left)*(W/r.width);
  const py = (e.clientY-r.top)*(H/r.height);
  mouseMath = {x:xfromPx(px), y:yfromPx(py)};
  redraw();
});

$$('.cbtn',$('#w-speckxy')).forEach(b=>b.addEventListener('click',()=>{
  const id = b.dataset.c;
  if(active.has(id)){active.delete(id); b.classList.remove('active')}
  else {active.add(id); b.classList.add('active')}
  redraw();
}));
