const svg = $('#spec-svg');
const W=820,H=400;
const ro = $('#spec-readout');
// nodes: {id,label,x,y,kind,containedIn:[]}  — "containedIn" = primes this one specializes TO
// edges go from smaller ideal (top) to bigger ideal (bottom).
// Spec C[x,y]. Take primes: (0), (y), (y-x^2), (x^2+y^2-1), and closed intersections
//  (y) ∩ (y-x^2) ⊃ origin = (x,y)
//  (y) ∩ (x^2+y^2-1) ⊃ (x-1,y) and (x+1,y)
//  (y-x^2) ∩ (x^2+y^2-1) ⊃ two real closed points at x satisfying x^4+x^2-1=0 (call them α,β) and two complex. I'll just mark two of them.
// For clarity, draw only a tractable subset.
const N = [
  {id:'0',     label:'(0)',         tier:0, color:'#b39ddb', desc:'2-dim generic point of the whole plane — residue field ℂ(x,y)'},
  {id:'y',     label:'(y)',         tier:1, color:'#58c4dd', desc:'generic point of the x-axis y=0'},
  {id:'yx2',   label:'(y − x²)',    tier:1, color:'#ffd866', desc:'generic point of the parabola y=x²'},
  {id:'circ',  label:'(x² + y² − 1)',tier:1,color:'var(--green)', desc:'generic point of the unit circle'},
  // closed points
  {id:'o',     label:'(x, y)',              tier:2, color:'#e07a5f', desc:'origin — lies on both y=0 and y=x²'},
  {id:'p1',    label:'(x − 1, y)',          tier:2, color:'#e07a5f', desc:'point (1,0) — on y=0 and on circle'},
  {id:'pm1',   label:'(x + 1, y)',          tier:2, color:'#e07a5f', desc:'point (−1,0) — on y=0 and on circle'},
  {id:'pc1',   label:'(x − α, y − α²)',     tier:2, color:'#e07a5f', desc:'intersection of parabola with circle (one real point, α²+α⁴=1)'},
  {id:'pc2',   label:'(x + α, y − α²)',     tier:2, color:'#e07a5f', desc:'the other real parabola∩circle point'},
];
const E = [
  ['0','y'],['0','yx2'],['0','circ'],
  ['y','o'],['yx2','o'],
  ['y','p1'],['circ','p1'],
  ['y','pm1'],['circ','pm1'],
  ['yx2','pc1'],['circ','pc1'],
  ['yx2','pc2'],['circ','pc2'],
];

// layout: three tiers
const yOf = t => 60 + t*150;
function layoutTier(ids,y){
  const n = ids.length;
  const pad = 80;
  ids.forEach((id,i)=>{
    const nd = N.find(x=>x.id===id);
    nd.x = pad + (W-2*pad)*(n===1?0.5:(i/(n-1)));
    nd.y = y;
  });
}
layoutTier(['0'], yOf(0));
layoutTier(['y','yx2','circ'], yOf(1));
layoutTier(['o','p1','pm1','pc1','pc2'], yOf(2));

let selected = null;

function downstream(id){
  // nodes that specialize from id (id ⊆ x): i.e., in closure
  const out = new Set([id]);
  let changed=true;
  while(changed){
    changed=false;
    for(const [a,b] of E){
      if(out.has(a) && !out.has(b)){out.add(b);changed=true}
    }
  }
  return out;
}
function upstream(id){
  const out = new Set([id]);
  let changed=true;
  while(changed){
    changed=false;
    for(const [a,b] of E){
      if(out.has(b) && !out.has(a)){out.add(a);changed=true}
    }
  }
  return out;
}

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // tier labels
  const tiers = [
    {t:0,label:'generic of plane'},
    {t:1,label:'curves (dim-1 primes)'},
    {t:2,label:'closed points (max ideals)'},
  ];
  for(const {t,label} of tiers){
    const txt = SVG('text',{x:20,y:yOf(t)+4,'font-size':12,fill:'#6c7787'});
    txt.textContent=label;
    svg.appendChild(txt);
  }
  // edges
  const down = selected? downstream(selected):new Set();
  const up = selected? upstream(selected):new Set();
  for(const [a,b] of E){
    const na = N.find(x=>x.id===a), nb = N.find(x=>x.id===b);
    let color='#2a3242', w=1;
    if(selected){
      if(down.has(a) && down.has(b)){color='#ffd866';w=1.6}
      else if(up.has(a) && up.has(b)){color='#58c4dd';w=1.4}
    }
    svg.appendChild(SVG('line',{x1:na.x,y1:na.y+12,x2:nb.x,y2:nb.y-12,stroke:color,'stroke-width':w,'stroke-opacity':0.85}));
  }
  // nodes
  for(const nd of N){
    const inDown = down.has(nd.id), inUp = up.has(nd.id);
    const isSel = nd.id===selected;
    const rad = nd.tier===0? 12 : (nd.tier===1?9:7);
    const fill = isSel?'#fff':nd.color;
    const stroke = isSel?'#fff': (selected? (inDown?'#ffd866':(inUp?'#58c4dd':'#2a3242')) : '#2a3242');
    const g = SVG('g',{style:'cursor:pointer'});
    g.appendChild(SVG('circle',{cx:nd.x,cy:nd.y,r:rad,fill,stroke,'stroke-width':2}));
    const t = SVG('text',{x:nd.x,y:nd.y+rad+16,'font-size':12,'text-anchor':'middle',fill:(isSel||inDown||inUp)?'#fff':'#9aa4b2'});
    t.textContent = nd.label;
    g.appendChild(t);
    g.addEventListener('click',()=>{selected = (selected===nd.id?null:nd.id); draw();});
    svg.appendChild(g);
  }
  // readout
  if(selected){
    const nd = N.find(x=>x.id===selected);
    const dn = [...downstream(selected)].filter(x=>x!==selected);
    const up2 = [...upstream(selected)].filter(x=>x!==selected);
    ro.innerHTML = `<div><b style="color:#fff">${nd.label}</b> — ${nd.desc}</div>
      <div class="small" style="color:var(--yellow);margin-top:.4rem">closure (specializes to): ${dn.map(i=>N.find(x=>x.id===i).label).join(', ')||'— only itself'}</div>
      <div class="small" style="color:var(--blue)">generization (specializes from): ${up2.map(i=>N.find(x=>x.id===i).label).join(', ')||'— none (this is a generic point)'}</div>`;
  } else {
    ro.innerHTML = `Click a node: the <span style="color:var(--yellow)">closure</span> is the node plus everything below. The <span style="color:var(--blue)">"generization"</span> is everything above.`;
  }
}
draw();

