/* =============================== SECTION 6: Fat points =============================== */
(function(){
  const svg = $('#fat-svg');
  const W=820,H=300;
  const ro = $('#fat-readout');
  const nInp = $('#fat-n'), nVal = $('#fat-nval'), pInp = $('#fat-p');

  // parse a polynomial like "1 + 2x + 3x^2 + 0.5x^4" into coefficient array
  function parseP(s){
    s = s.replace(/\s+/g,'').replace(/−/g,'-');
    // split on +/- keeping sign
    const terms = s.split(/(?=[+-])/).filter(Boolean);
    const coeffs = [];
    for(const t of terms){
      const m = t.match(/^([+-]?)(\d*\.?\d*)(\*?)(x(\^(\d+))?)?$/);
      if(!m) return null;
      const sign = m[1]==='-'?-1:1;
      let c = m[2]===''||m[2]==='+'||m[2]==='-' ? 1 : parseFloat(m[2]);
      if(isNaN(c)) c=1;
      let deg = 0;
      if(m[4]){ deg = m[6]? parseInt(m[6]):1; }
      while(coeffs.length<=deg) coeffs.push(0);
      coeffs[deg] += sign*c;
    }
    return coeffs;
  }

  function draw(){
    const n = parseInt(nInp.value);
    nVal.textContent = n;
    const coeffs = parseP(pInp.value) || [0];
    // truncate to degree < n
    const trunc = coeffs.slice(0,n);
    while(trunc.length<n) trunc.push(0);

    while(svg.firstChild) svg.removeChild(svg.firstChild);

    // LEFT: the "fat point" itself, as a dot with rings
    const leftCx = 180, leftCy = 150;
    const title1 = SVG('text',{x:leftCx,y:40,'font-size':13,'text-anchor':'middle',fill:'#fff'});
    title1.textContent = `Spec ℂ[x]/(x${n===1?'':'ⁿ'.replace('ⁿ',sup(n))})`;
    svg.appendChild(title1);
    // rings: one per jet level
    for(let k=n;k>=1;k--){
      const r = 18 + (k-1)*11;
      svg.appendChild(SVG('circle',{cx:leftCx,cy:leftCy,r,fill:'#ffd866','fill-opacity':0.06 + 0.06*(n-k)/Math.max(n-1,1),stroke:'#ffd866','stroke-opacity':0.35,'stroke-width':1}));
    }
    svg.appendChild(SVG('circle',{cx:leftCx,cy:leftCy,r:5,fill:'#ffd866'}));
    const tag = SVG('text',{x:leftCx,y:leftCy+90,'font-size':12,'text-anchor':'middle',fill:'#9aa4b2'});
    tag.textContent = `length = ${n}`;
    svg.appendChild(tag);
    const tag2 = SVG('text',{x:leftCx,y:leftCy+110,'font-size':11,'text-anchor':'middle',fill:'#6c7787'});
    tag2.textContent = n===1?'just a point':(n===2?'point + tangent direction':`point + ${n-1} derivatives`);
    svg.appendChild(tag2);

    // MIDDLE/RIGHT: graph of p(x), with zoomed-in "lens" at origin showing n-th Taylor approx
    const gx0 = 400, gx1 = 800;
    const gy0 = 60, gy1 = 260;
    const xs = x => gx0 + ((x+1.5)/3)*(gx1-gx0);
    const ys = y => gy1 - ((y+4)/12)*(gy1-gy0);  // y range roughly -4..8
    // plot axes
    svg.appendChild(SVG('line',{x1:gx0,y1:ys(0),x2:gx1,y2:ys(0),stroke:'#3a4558'}));
    svg.appendChild(SVG('line',{x1:xs(0),y1:gy0,x2:xs(0),y2:gy1,stroke:'#3a4558'}));
    const xl=SVG('text',{x:gx1-6,y:ys(0)-6,'font-size':11,'text-anchor':'end',fill:'#6c7787'});xl.textContent='x';svg.appendChild(xl);

    // full poly p(x)
    const pvals = [];
    const evalP = (x,c)=>{let y=0;for(let i=c.length-1;i>=0;i--)y=y*x+c[i];return y;};
    for(let i=0;i<=120;i++){
      const t = -1.5 + 3*i/120;
      pvals.push([xs(t), ys(evalP(t,coeffs))]);
    }
    svg.appendChild(SVG('polyline',{points:pvals.map(p=>p.join(',')).join(' '),fill:'none',stroke:'#58c4dd','stroke-width':2}));
    const plab = SVG('text',{x:gx1-6,y:gy0+14,'font-size':12,'text-anchor':'end',fill:'#58c4dd'});
    plab.textContent='p(x)';
    svg.appendChild(plab);

    // truncated p mod x^n
    const tvals=[];
    for(let i=0;i<=120;i++){
      const t = -1.5 + 3*i/120;
      tvals.push([xs(t), ys(evalP(t,trunc))]);
    }
    svg.appendChild(SVG('polyline',{points:tvals.map(p=>p.join(',')).join(' '),fill:'none',stroke:'#ffd866','stroke-width':2,'stroke-dasharray':'5 4'}));
    const tlab = SVG('text',{x:gx1-6,y:gy0+30,'font-size':12,'text-anchor':'end',fill:'#ffd866'});
    tlab.textContent='p(x) mod xⁿ';
    svg.appendChild(tlab);

    // infinitesimal zone: a tiny band around x=0 indicating what the fat point "sees"
    const band = SVG('rect',{x:xs(-0.02),y:gy0,width:xs(0.02)-xs(-0.02),height:gy1-gy0,fill:'#ffd866','fill-opacity':0.12});
    svg.appendChild(band);

    // readout: show the truncated polynomial
    const polyFmt = c=>{
      const parts=[];
      for(let i=0;i<c.length;i++){
        if(Math.abs(c[i])<1e-9) continue;
        const coef = c[i];
        let s = (i===0)? coef.toString() : (Math.abs(coef)===1? (coef<0?'−':'') : `${coef<0?'−':''}${Math.abs(coef)}`);
        const xp = i===0?'':(i===1?'x':`x${sup(i)}`);
