      for(let i=0;i<c.length;i++){
        const v = c[i];
        if(Math.abs(v)<1e-10) continue;
        const sign = v<0?'−':(parts.length?'+':'');
        const absV = Math.abs(v);
        const co = (i>0 && Math.abs(absV-1)<1e-10)? '' : (Number.isInteger(absV)?absV:absV.toFixed(3).replace(/\.?0+$/,''));
        const xp = i===0?'':(i===1?'x':`x${sup(i)}`);
