/* =============================== SECTION 6: Fat points =============================== */
(function(){
  const svg = $('#fat-svg');
  const W=820,H=300;
  const ro = $('#fat-readout');
  const nInp = $('#fat-n'), nVal = $('#fat-nval'), pInp = $('#fat-p');

  // parse a polynomial like "1 + 2x + 3x^2 + 0.5x^4" into coefficient array
  function parseP(s){
    s = s.replace(/\s+/g,'').replace(/−/g,'-');
    // split on +/- keeping sign
    const terms = s.split(/(?=[+-])/).filter(Boolean);
    const coeffs = [];
    for(const t of terms){
      const m = t.match(/^([+-]?)(\d*\.?\d*)(\*?)(x(\^(\d+))?)?$/);
      if(!m) return null;
      const sign = m[1]==='-'?-1:1;
      let c = m[2]===''||m[2]==='+'||m[2]==='-' ? 1 : parseFloat(m[2]);
      if(isNaN(c)) c=1;
      let deg = 0;
      if(m[4]){ deg = m[6]? parseInt(m[6]):1; }
      while(coeffs.length<=deg) coeffs.push(0);
      coeffs[deg] += sign*c;
    }
    return coeffs;
  }

  function draw(){
    const n = parseInt(nInp.value);
    nVal.textContent = n;
    const coeffs = parseP(pInp.value) || [0];
    // truncate to degree < n
    const trunc = coeffs.slice(0,n);
    while(trunc.length<n) trunc.push(0);

    while(svg.firstChild) svg.removeChild(svg.firstChild);

    // LEFT: the "fat point" itself, as a dot with rings
    const leftCx = 180, leftCy = 150;
    const title1 = SVG('text',{x:leftCx,y:40,'font-size':13,'text-anchor':'middle',fill:'#fff'});
    title1.textContent = `Spec ℂ[x]/(x${n===1?'':'ⁿ'.replace('ⁿ',sup(n))})`;
    svg.appendChild(title1);
    // rings: one per jet level
    for(let k=n;k>=1;k--){
      const r = 18 + (k-1)*11;
      svg.appendChild(SVG('circle',{cx:leftCx,cy:leftCy,r,fill:'#ffd866','fill-opacity':0.06 + 0.06*(n-k)/Math.max(n-1,1),stroke:'#ffd866','stroke-opacity':0.35,'stroke-width':1}));
    }
    svg.appendChild(SVG('circle',{cx:leftCx,cy:leftCy,r:5,fill:'#ffd866'}));
    const tag = SVG('text',{x:leftCx,y:leftCy+90,'font-size':12,'text-anchor':'middle',fill:'#9aa4b2'});
    tag.textContent = `length = ${n}`;
    svg.appendChild(tag);
    const tag2 = SVG('text',{x:leftCx,y:leftCy+110,'font-size':11,'text-anchor':'middle',fill:'#6c7787'});
    tag2.textContent = n===1?'just a point':(n===2?'point + tangent direction':`point + ${n-1} derivatives`);
    svg.appendChild(tag2);

    // MIDDLE/RIGHT: graph of p(x), with zoomed-in "lens" at origin showing n-th Taylor approx
    const gx0 = 400, gx1 = 800;
