        const xp = i===0?'':(i===1?'x':`x${sup(i)}`);
        parts.push(`${parts.length?' ':''}${sign}${parts.length||v<0?' ':''}${co}${xp}`);
      }
      return parts.join('').trim()||'0';
    };
    function sup(n){return ''+[...String(n)].map(d=>'⁰¹²³⁴⁵⁶⁷⁸⁹'[+d]).join('')}
    ro.innerHTML =
      `<div>p(x) = <span style="color:var(--blue)">${fmt(coeffs)}</span></div>`+
      `<div>image in ℂ[x]/(x${sup(n)}) = <span style="color:var(--yellow)">${fmt(trunc)}</span></div>`+
