const svg = $('#glue-svg');
const W=820, H=440;
const ro = $('#glue-readout');

// Top: circle representing P^1(R). Angle θ ∈ [0, 2π). x = tan(θ/2) via stereographic from north pole.
// Two charts U, V below.
const cx = W/2, cy = 120, rad = 80;
// Draw circle
svg.appendChild(SVG('circle',{cx,cy,r:rad,fill:'none',stroke:'#3a4558','stroke-width':1.5}));
const tN = SVG('text',{x:cx,y:cy-rad-8,'font-size':12,'text-anchor':'middle',fill:'#e07a5f'});
tN.textContent='∞ (origin of V)';
svg.appendChild(tN);
const tS = SVG('text',{x:cx,y:cy+rad+18,'font-size':12,'text-anchor':'middle',fill:'#ffd866'});
tS.textContent='0 (origin of U)';
svg.appendChild(tS);
svg.appendChild(SVG('circle',{cx,cy:cy-rad,r:4,fill:'#e07a5f'})); // N
svg.appendChild(SVG('circle',{cx,cy:cy+rad,r:4,fill:'#ffd866'})); // S (x=0)
// title
const tP = SVG('text',{x:cx,y:30,'font-size':13,'text-anchor':'middle',fill:'#fff'});
tP.textContent = 'ℙ¹ (real picture)';
svg.appendChild(tP);

// Two affine charts as horizontal number lines
const uY = 290, vY = 380;
const axL = 60, axR = W-60, axMid = (axL+axR)/2;
svg.appendChild(SVG('line',{x1:axL,y1:uY,x2:axR,y2:uY,stroke:'#3a4558'}));
svg.appendChild(SVG('line',{x1:axL,y1:vY,x2:axR,y2:vY,stroke:'#3a4558'}));
const uLbl = SVG('text',{x:axL,y:uY-14,'font-size':13,fill:'#ffd866'});
uLbl.textContent='U = Spec k[x]   — the x-chart';
svg.appendChild(uLbl);
const vLbl = SVG('text',{x:axL,y:vY-14,'font-size':13,fill:'#e07a5f'});
vLbl.textContent='V = Spec k[y]   — the y-chart   (y = 1/x on overlap)';
svg.appendChild(vLbl);

// tick marks
function ticks(y,col){
  for(let k=-4;k<=4;k++){
    if(k===0){
      svg.appendChild(SVG('circle',{cx:axMid,cy:y,r:4,fill:col}));
      const t = SVG('text',{x:axMid,y:y+18,'font-size':11,'text-anchor':'middle',fill:col});
      t.textContent='0';
      svg.appendChild(t);
    } else {
      const px = axMid + k*((axR-axL)/2)/4;
      svg.appendChild(SVG('line',{x1:px,y1:y-4,x2:px,y2:y+4,stroke:'#3a4558'}));
      const t = SVG('text',{x:px,y:y+18,'font-size':11,'text-anchor':'middle',fill:'#6c7787'});
      t.textContent=k;
      svg.appendChild(t);
    }
  }
}
ticks(uY,'#ffd866');
ticks(vY,'#e07a5f');

// Point dots and connecting lines
const dotP = SVG('circle',{r:7,fill:'#58c4dd',stroke:'#fff','stroke-width':1.5,style:'cursor:grab'});
const dotU = SVG('circle',{r:7,fill:'#ffd866',stroke:'#fff','stroke-width':1.5});
const dotV = SVG('circle',{r:7,fill:'#e07a5f',stroke:'#fff','stroke-width':1.5});
const lineUV = SVG('line',{stroke:'#58c4dd','stroke-width':1,'stroke-opacity':0.3,'stroke-dasharray':'3 4'});
const linePU = SVG('line',{stroke:'#ffd866','stroke-width':1,'stroke-opacity':0.4,'stroke-dasharray':'3 4'});
const linePV = SVG('line',{stroke:'#e07a5f','stroke-width':1,'stroke-opacity':0.4,'stroke-dasharray':'3 4'});
svg.appendChild(lineUV); svg.appendChild(linePU); svg.appendChild(linePV);
svg.appendChild(dotU); svg.appendChild(dotV); svg.appendChild(dotP);

// state
let theta = Math.PI/3; // starting angle, on the right side

function pxForX(x){
  // squash R -> axis length using x ↦ x/(1+|x|)*half, but we also cap to axis range
  const half = (axR-axL)/2;
  const comp = Math.atan(x/3)/(Math.PI/2); // ∈ (-1,1)
  return axMid + comp*half;
}
function update(){
  // Position on circle: N at top (0,−r). Use standard angle: θ=0 at east, CCW.
  const Px = cx + rad*Math.cos(theta);
  const Py = cy - rad*Math.sin(theta);
  dotP.setAttribute('cx',Px); dotP.setAttribute('cy',Py);

  // Stereographic: project from N=(0,−r) (TOP of circle; "north pole" in our SVG is up = y small)
  // In our coords, (cx, cy-rad) is the north pole. Use stereographic:
  //   x = (point_x - cx) / (1 - (point_y_above_center)/(-r))  … let's just derive:
  // Map point on unit circle to x via (sinθ)/(1 - cosθ)?  We want:
  //   south pole (θ = -π/2 in our convention, bottom) ↦ x = 0
  //   north pole (θ = +π/2, top) ↦ x = ∞
  //   east (θ=0) ↦ x = 1
  //   west (θ=π) ↦ x = -1
  // Using tan((θ/2 + π/4))? Let's construct: with angle φ measured from south pole.
  // Let φ = θ + π/2 (so φ=0 at south). Then x = tan(φ/2) gives:
  //   φ=0 → x=0 ✓
  //   φ=π → x=∞ ✓
  //   φ=π/2 (east) → x=1 ✓
  //   φ=-π/2 (west) → x=-1 ✓
  const phi = theta + Math.PI/2;
  let x, y, xInf=false, yInf=false;
  // normalize phi to (-π, π]
  let phiN = ((phi+Math.PI)%(2*Math.PI)+2*Math.PI)%(2*Math.PI)-Math.PI;
  if(Math.abs(Math.abs(phiN)-Math.PI)<1e-6){ xInf=true; }
  else { x = Math.tan(phiN/2); }
  if(Math.abs(phiN)<1e-6){ yInf=true; }
  else { y = 1/Math.tan(phiN/2); }

  // U dot
  if(xInf){
    dotU.setAttribute('opacity','0.2');
    dotU.setAttribute('cx',axR); dotU.setAttribute('cy',uY);
    linePU.setAttribute('stroke-opacity',0.1);
  } else {
    dotU.setAttribute('opacity','1');
    const ux = pxForX(x);
    dotU.setAttribute('cx',ux); dotU.setAttribute('cy',uY);
    linePU.setAttribute('x1',Px); linePU.setAttribute('y1',Py);
    linePU.setAttribute('x2',ux); linePU.setAttribute('y2',uY);
    linePU.setAttribute('stroke-opacity',0.4);
  }
  // V dot
  if(yInf){
    dotV.setAttribute('opacity','0.2');
    dotV.setAttribute('cx',axR); dotV.setAttribute('cy',vY);
    linePV.setAttribute('stroke-opacity',0.1);
  } else {
    dotV.setAttribute('opacity','1');
    const vx = pxForX(y);
    dotV.setAttribute('cx',vx); dotV.setAttribute('cy',vY);
    linePV.setAttribute('x1',Px); linePV.setAttribute('y1',Py);
    linePV.setAttribute('x2',vx); linePV.setAttribute('y2',vY);
    linePV.setAttribute('stroke-opacity',0.4);
  }
  // connect U and V dots
  if(!xInf && !yInf){
    lineUV.setAttribute('x1',dotU.getAttribute('cx')); lineUV.setAttribute('y1',uY);
    lineUV.setAttribute('x2',dotV.getAttribute('cx')); lineUV.setAttribute('y2',vY);
    lineUV.setAttribute('stroke-opacity',0.3);
  } else {
    lineUV.setAttribute('stroke-opacity',0);
  }
  // Readout
  const xStr = xInf?'<span style="color:var(--pink)">undefined (this point ∉ U)</span>':x.toFixed(3);
  const yStr = yInf?'<span style="color:var(--yellow)">undefined (this point ∉ V)</span>':y.toFixed(3);
  const whichCharts = (xInf?'V only':(yInf?'U only':'both charts (U ∩ V)'));
  ro.innerHTML =
    `<div>point's coordinates:   x = <span style="color:var(--yellow)">${xStr}</span>  ·  y = <span style="color:var(--pink)">${yStr}</span></div>`+
    `<div class="small">this point is covered by: ${whichCharts}` +
    ((!xInf && !yInf)?` · check: x·y = ${(x*y).toFixed(3)} (should be 1)`:'') +
    `</div>`;
}
update();

// drag
let dragging=false;
function setFromPx(e){
  const r = svg.getBoundingClientRect();
  const px = (e.clientX-r.left)*(W/r.width);
  const py = (e.clientY-r.top)*(H/r.height);
  // compute theta
  theta = Math.atan2(cy-py, px-cx);
  update();
}
