  //   φ=-π/2 (west) → x=-1 ✓
  const phi = theta + Math.PI/2;
  let x, y, xInf=false, yInf=false;
  // normalize phi to (-π, π]
  let phiN = ((phi+Math.PI)%(2*Math.PI)+2*Math.PI)%(2*Math.PI)-Math.PI;
  if(Math.abs(Math.abs(phiN)-Math.PI)<1e-6){ xInf=true; }
  else { x = Math.tan(phiN/2); }
  if(Math.abs(phiN)<1e-6){ yInf=true; }
  else { y = 1/Math.tan(phiN/2); }

  // U dot
  if(xInf){
    dotU.setAttribute('opacity','0.2');
    dotU.setAttribute('cx',axR); dotU.setAttribute('cy',uY);
    linePU.setAttribute('stroke-opacity',0.1);
  } else {
    dotU.setAttribute('opacity','1');
    const ux = pxForX(x);
    dotU.setAttribute('cx',ux); dotU.setAttribute('cy',uY);
    linePU.setAttribute('x1',Px); linePU.setAttribute('y1',Py);
    linePU.setAttribute('x2',ux); linePU.setAttribute('y2',uY);
    linePU.setAttribute('stroke-opacity',0.4);
  }
  // V dot
  if(yInf){
    dotV.setAttribute('opacity','0.2');
    dotV.setAttribute('cx',axR); dotV.setAttribute('cy',vY);
    linePV.setAttribute('stroke-opacity',0.1);
  } else {
    dotV.setAttribute('opacity','1');
    const vx = pxForX(y);
    dotV.setAttribute('cx',vx); dotV.setAttribute('cy',vY);
    linePV.setAttribute('x1',Px); linePV.setAttribute('y1',Py);
    linePV.setAttribute('x2',vx); linePV.setAttribute('y2',vY);
    linePV.setAttribute('stroke-opacity',0.4);
  }
  // connect U and V dots
  if(!xInf && !yInf){
    lineUV.setAttribute('x1',dotU.getAttribute('cx')); lineUV.setAttribute('y1',uY);
    lineUV.setAttribute('x2',dotV.getAttribute('cx')); lineUV.setAttribute('y2',vY);
    lineUV.setAttribute('stroke-opacity',0.3);
  } else {
    lineUV.setAttribute('stroke-opacity',0);
  }
  // Readout
  const xStr = xInf?'<span style="color:var(--pink)">undefined (this point ∉ U)</span>':x.toFixed(3);
  const yStr = yInf?'<span style="color:var(--yellow)">undefined (this point ∉ V)</span>':y.toFixed(3);
  const whichCharts = (xInf?'V only':(yInf?'U only':'both charts (U ∩ V)'));
  ro.innerHTML =
    `<div>point's coordinates:   x = <span style="color:var(--yellow)">${xStr}</span>  ·  y = <span style="color:var(--pink)">${yStr}</span></div>`+
    `<div class="small">this point is covered by: ${whichCharts}` +
    ((!xInf && !yInf)?` · check: x·y = ${(x*y).toFixed(3)} (should be 1)`:'') +
    `</div>`;
}
update();

