function setFromPx(e){
  const r = svg.getBoundingClientRect();
  const px = (e.clientX-r.left)*(W/r.width);
  const py = (e.clientY-r.top)*(H/r.height);
  // compute theta
  theta = Math.atan2(cy-py, px-cx);
  update();
}
dotP.addEventListener('mousedown',e=>{dragging=true; e.preventDefault();});
window.addEventListener('mousemove',e=>{if(dragging) setFromPx(e);});
window.addEventListener('mouseup',()=>{dragging=false;});
svg.addEventListener('click',setFromPx);

