svg.appendChild(SVG('line',{x1:40,y1:baseY,x2:W-40,y2:baseY,stroke:'var(--line)','stroke-width':1.5}));
const baseLabel = SVG('text',{x:W-40,y:baseY+22,'font-size':12,'text-anchor':'end',fill:'var(--mute)'});
baseLabel.textContent = 'Spec ℤ  (base)';
svg.appendChild(baseLabel);
// columns: primes 2,3,5,7,11, and a rightmost generic column
const cols = [
  {x:120, label:'(2)',  col:'var(--cyan)',   fiber:'𝔸¹_{𝔽₂}'},
  {x:220, label:'(3)',  col:'var(--green)',  fiber:'𝔸¹_{𝔽₃}'},
  {x:320, label:'(5)',  col:'var(--yellow)', fiber:'𝔸¹_{𝔽₅}'},
  {x:420, label:'(7)',  col:'var(--pink)',   fiber:'𝔸¹_{𝔽₇}'},
  {x:520, label:'(11)', col:'var(--violet)', fiber:'𝔸¹_{𝔽₁₁}'},
  {x:700, label:'(0)',  col:'var(--blue)',   fiber:'𝔸¹_{ℚ}  (generic fiber)'},
];
for(const c of cols){
  // vertical fiber line
  svg.appendChild(SVG('line',{x1:c.x,y1:40,x2:c.x,y2:baseY-4,stroke:c.col,'stroke-width':1.5,'stroke-opacity':0.8}));
  // base point
  svg.appendChild(SVG('circle',{cx:c.x,cy:baseY,r:4,fill:c.col,stroke:'#fff','stroke-width':1}));
  // base label
  const lb = SVG('text',{x:c.x,y:baseY+22,'font-size':12,'text-anchor':'middle',fill:c.col});
  lb.textContent = c.label;
  svg.appendChild(lb);
  // fiber label (top)
  const lf = SVG('text',{x:c.x,y:32,'font-size':12,'text-anchor':'middle',fill:c.col});
  lf.textContent = c.fiber;
  svg.appendChild(lf);
  // a few closed points along the fiber
  for(let k=0;k<5;k++){
    const y = 60 + k*32;
    if(y > baseY-16) break;
    svg.appendChild(SVG('circle',{cx:c.x,cy:y,r:3,fill:c.col,opacity:0.85}));
  }
}
